public int minSpaceWastedKResizing(int[] nums, int k) {
    int n = nums.length;
    int[][] dp = new int[n + 1][k + 1];
    int[] sum = new int[n + 1];

    for (int i = 0; i <= n; i++) {
        Arrays.fill(dp[i], Integer.MAX_VALUE / 3);
    }

    dp[0][0] = 0;
    for (int i = 1; i <= n; i++) {
        sum[i] = sum[i - 1] + nums[i - 1];
        int max_val = nums[i - 1];
        for (int j = i - 1; j >= 0; j--) {
            max_val = Math.max(max_val, nums[j]);
            int waste = max_val * (i - j) - (sum[i] - sum[j]);
            for (int c = 0; c < k; c++) {
                dp[i][c + 1] = Math.min(dp[i][c + 1], dp[j][c] + waste);
            }
        }
    }
    return dp[n][k];
}
